import React, { useContext } from "react";
import { Routes, Route } from "react-router-dom";

// Ensure these paths match your actual folder structure
import WatchList from "./WatchList"; 
import Summary from "./Summary";
import Orders from "./Orders";
import Holdings from "./Holdings";
import BuyActionWindow from "./BuyActionWindow"; 
import { GeneralContext } from "./GeneralContext";

const Dashboard = () => {
  // Use the context to check if the popup should be visible
  const { isBuyWindowOpen } = useContext(GeneralContext);

  return (
    <div className="dashboard-container">
      {/* Sidebar */}
      <WatchList />

      {/* Main Content Area */}
      <div className="content">
        <Routes>
          <Route path="/" element={<Summary />} />
          <Route path="/orders" element={<Orders />} />
          <Route path="/holdings" element={<Holdings />} />
        </Routes>
      </div>

      {/* The Popup Logic */}
      {isBuyWindowOpen && <BuyActionWindow mode="BUY" />}
    </div>
  );
};

// CRITICAL FIX: This line solves the "does not contain a default export" error
export default Dashboard;
